"""
mkt-christ | 2 Samuel 22-23
Run: python3 scripts/zc-christ-2samuel-22-23.py

Ch 22 (= Psalm 18): David's victory hymn as messianic song; the anointed king's theology of rescue
Ch 23: Last words as messianic testament; gibbôrîm as the community of the servant-king
"""

import json
import pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


SAMUEL2_CHRIST_CH22_23 = {
    "22": {
        "1": "<p>2 Samuel 22 is David's victory hymn — the song of the anointed king (<em>māšîaḥ</em>, v51) who was delivered from all his enemies. It stands at the end of the Samuel narrative as the interpretive key to the entire David story. In its deepest register, it is the song Christ himself will sing — cited in Heb 2:12 ('I will tell of your name to my brothers; in the midst of the congregation I will sing your praise') as the risen Son's praise among his people. The ultimate singer of this psalm is not David but the Davidic Messiah who was delivered from death itself.</p>",
        "2": "<p>'My rock, my fortress, my deliverer.' Christ as the Rock is the NT's direct application of this cluster: 1 Cor 10:4 ('the Rock was Christ'); Matt 7:24-25 (the wise man who builds on the rock); 1 Pet 2:6-8 (Christ as the cornerstone, both precious foundation and stumbling stone). The geological metaphors David uses — rock, fortress, stronghold — become in the NT the vocabulary for Christ as the ultimate foundation of the new covenant community. What YHWH was to David (the rock who did not move), Christ is to his people.</p>",
        "3": "<p>'My God, my rock, in whom I take refuge, my shield, and the horn of my salvation, my stronghold and my refuge, my savior.' The horn of salvation (<em>qeren yišʿî</em>) is the precise phrase Zechariah uses in his Benedictus: 'He has raised up a horn of salvation for us in the house of his servant David' (Luke 1:69). Zechariah's Spirit-inspired proclamation at John the Baptist's birth identifies Jesus as the fulfillment of what David was singing about — the 'horn of salvation' David celebrated is the Davidic Messiah, Jesus of Nazareth.</p>",
        "4": "<p>'I call upon YHWH, who is worthy to be praised, and I am saved from my enemies.' Christ is the one who called upon YHWH in the days of his flesh — 'he offered up prayers and supplications, with loud crying and tears, to him who was able to save him from death, and he was heard because of his reverence' (Heb 5:7). The pattern of David's cry-and-rescue is fulfilled in Gethsemane and Easter morning: the anointed king cried to YHWH, was heard, and was delivered — not from the cross, but through it and out the other side.</p>",
        "5": "<p>'For the waves of death encompassed me, the torrents of destruction assailed me.' The cords/waves of death surrounding the psalmist find their ultimate fulfillment in the one who descended into death itself. The NT confesses that Christ experienced the full force of <em>ḥeḇlê māweṯ</em> — not merely near-death but actual death. 'He tasted death for everyone' (Heb 2:9); he was 'delivered up to death' (Rom 4:25). What David describes as mortal danger surrounding him, Christ entered completely — so that he could emerge from the other side as the firstborn from the dead.</p>",
        "6": "<p>'The cords of Sheol entangled me; the snares of death confronted me.' The language of Sheol's cords and death's snares is the language Christ exhausted and overcame. Acts 2:24: 'God raised him up, loosing the pangs of death, because it was not possible for him to be held by it.' The 'pangs/cords' (<em>ṓdines</em> in LXX = <em>ḥeḇlîm</em>) of death that Peter describes being loosed at the resurrection are the same cords of Sheol that 2 Sam 22:6 describes surrounding David. Christ is the one who entered Sheol's grip and burst it open.</p>",
        "7": "<p>'In my distress I called upon YHWH; to my God I called. From his temple he heard my voice.' Christ's prayer was heard — 'he was heard because of his reverence' (Heb 5:7). The cross and empty tomb are the proof that YHWH heard the cry of his anointed Son. John 11:42: 'I knew that you always hear me.' The Gethsemane prayer ('Father, if possible, let this cup pass') was answered not by removal of the cup but by the resurrection that followed the drinking of it. YHWH's hearing from his heavenly temple means not prevention of suffering but vindication through it.</p>",
        "8": "<p>The cosmic theophany of vv8-16 — earth shaking, smoke, fire, darkened skies, YHWH the divine warrior responding to his anointed's cry — is the pattern that Revelation uses for Christ's return as the divine warrior (Rev 19:11-16). The theophany-response to the anointed king's cry is the template for the Parousia: just as YHWH descended in cosmic power to rescue David, Christ will come in power and great glory to vindicate his people. The language of Matt 24:29-30 (sun darkened, powers shaken, the Son of Man coming on clouds) is the fulfillment-theophany of 2 Sam 22:8-16.</p>",
        "9": "<p>'Smoke went up from his nostrils, and devouring fire from his mouth.' The divine warrior's fire that protects his anointed is the same fire that will consume his enemies at the end. 2 Thess 1:7-8: 'the Lord Jesus is revealed from heaven with his mighty angels in flaming fire, inflicting vengeance on those who do not know God.' The fire of YHWH's intervention for David is the prototype of the final fire of Christ's judgment — protective for the righteous, consuming for the ungodly. The same reality experienced differently depending on one's covenant status.</p>",
        "10": "<p>'He bowed the heavens and came down.' The descent theophany points to the incarnation as the supreme divine descent. The language of 2 Sam 22:10 — YHWH bowing the heavens to come to his servant's rescue — is transformed by the incarnation: the ultimate 'coming down' is not a theophanic storm but the Word becoming flesh (John 1:14). Phil 2:7-8: he 'emptied himself, taking the form of a servant, being born in the likeness of men.' The cosmic descent of YHWH to rescue David is the shadow of the incarnational descent of the Son to rescue humanity.</p>",
        "11": "<p>'He rode on a cherub and flew; he was seen on the wings of the wind.' The divine warrior riding the cherubim-throne is the imagery behind the ascension and Parousia. Acts 1:9: 'as they were looking on, he was lifted up, and a cloud took him out of their sight.' Rev 14:14: 'one like a son of man, sitting on the cloud.' The rider-on-clouds motif from the ANE, which 2 Sam 22 applies to YHWH coming to rescue David, is applied in Revelation to Christ's universal lordship. The cloud-rider who responds to David's cry is identified in the NT as the Son of Man.</p>",
        "12": "<p>'He made darkness around him his canopy, thick clouds, a gathering of water.' The darkness around YHWH in theophany reaches its fulfillment in the three hours of darkness at the cross (Matt 27:45; Luke 23:44-45). The darkness that conceals divine glory in the OT theophanies becomes the darkness of divine judgment and concealment at Calvary — the moment when the Father's face was hidden from the Son ('My God, my God, why have you forsaken me,' Ps 22:1 / Matt 27:46). The darkened theophany of rescue becomes the darkened theophany of the cross-judgment.</p>",
        "13": "<p>'Out of the brightness before him hailstones and coals of fire broke through the clouds.' The fire from YHWH that protects David from his enemies is the same fire that reveals truth. Christ himself is the one who 'baptizes with the Holy Spirit and fire' (Matt 3:11; Luke 3:16) — the Pentecost fire (Acts 2:3, tongues of fire distributed) is the arrival of the divine warrior's fire-presence, now poured out not for military victory over nations but for the empowerment of the covenant community for witness.</p>",
        "14": "<p>'YHWH thundered from heaven, and the Most High uttered his voice.' The divine voice from heaven — the thunder that signals YHWH's response to his anointed — is heard three times in the Gospel accounts as the Father's direct speech: at Jesus's baptism ('You are my beloved Son,' Mark 1:11), at the transfiguration ('This is my beloved Son; listen to him,' Mark 9:7), and in John 12:28 ('I have glorified it, and I will glorify it again'), where bystanders mistake it for thunder. The divine voice that answers David's cry culminates in the Father's voice answering and identifying his Son.</p>",
        "15": "<p>'And he sent out arrows and scattered them; lightning, and routed them.' Christ's conquest of his enemies is not military but consists in driving out the ruler of this world (John 12:31), binding the strong man (Matt 12:29), and disarming principalities and powers (Col 2:15). The divine warrior's lightning-arrows that scatter David's enemies are the type of Christ's authoritative word — 'the sword of the Spirit, which is the word of God' (Eph 6:17; Heb 4:12: 'the word of God is living and active, sharper than any two-edged sword').</p>",
        "16": "<p>'Then the channels of the sea were seen, and the foundations of the world were laid bare, at the rebuke of YHWH.' The cosmic exposure of sea-floor and earth-foundations at YHWH's rebuke echoes the Exodus sea-crossing and points to Christ's resurrection as the definitive cosmic event. Rev 20:11: 'from his presence earth and sky fled away, and no place was found for them.' The final judgment dissolves the present order — sea giving up its dead, death and Hades giving up theirs (Rev 20:13) — which is the eschatological fulfillment of the cosmic disruption 2 Sam 22:16 describes at the level of an individual rescue.</p>",
        "17": "<p>'He sent from on high, he took me; he drew me out of many waters.' Christ is the one who descended to draw his people out of the many waters of death and chaos. The 'drawn-out-one' motif (the name Moses = <em>Mōšeh</em>, drawn from the water) finds its ultimate fulfillment in the resurrection: Christ is pulled out of the waters of death, and in his resurrection he draws his people with him — 'if we have died with him, we will also live with him' (2 Tim 2:11; cf. Rom 6:3-5).</p>",
        "18": "<p>'He rescued me from my strong enemy, from those who hated me, for they were too mighty for me.' This is the Christological key to substitution: the enemy was too strong for David; YHWH rescued him. For humanity, the enemy — sin, death, the law's condemnation — was too strong for any human to overcome. Christ enters the arena where the enemy has overwhelmed humanity and conquers from within. 1 Cor 15:26: 'the last enemy to be destroyed is death.' Christ defeats the enemy that was too mighty for us, doing what we could not do for ourselves.</p>",
        "19": "<p>'They confronted me in the day of my calamity, but YHWH was my support.' Christ's 'day of calamity' was the cross — the day when all the forces of opposition confronted him simultaneously (betrayal, abandonment, false trial, torture, death). Yet 'YHWH was my support' — Acts 2:24: 'God raised him up, loosing the pangs of death, because it was not possible for him to be held by it.' The Father's support of the Son at the moment of maximum calamity is the resurrection. Every experience of divine support in the David narrative is a rehearsal for the ultimate support: Easter morning.</p>",
        "20": "<p>'He brought me out into a broad place; he rescued me, because he delighted in me.' The Father's delight in the Son is the explicit language of the baptism and transfiguration: 'This is my beloved Son, with whom I am well pleased' (Matt 3:17; 17:5). The rescue of the anointed king 'because he delighted in me' is the grace-ground of the resurrection: the Father raised the Son not because of human merit but because of the eternal love-relationship between Father and Son. The Son's rescue is the overflow of the Father's delight — and that delight extends to all who are in the Son (Eph 1:6: 'accepted in the beloved').</p>",
        "21": "<p>'YHWH dealt with me according to my righteousness.' Where David's righteousness claims (vv21-25) are partial and provisional — he is covenant-faithful relative to his enemies but not sinlessly perfect — Christ's righteousness is absolute and complete. He is 'holy, innocent, unstained, separated from sinners' (Heb 7:26). The righteousness that David could only approximate, Christ embodies fully. And the exchange: 'For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God' (2 Cor 5:21). David's righteousness claim becomes Christ's actual righteousness imputed to his people.</p>",
        "22": "<p>'For I have kept the ways of YHWH and have not wickedly departed from my God.' Christ is the one who kept all YHWH's ways without exception — 'I always do the things that are pleasing to him' (John 8:29); 'I have kept my Father's commandments and abide in his love' (John 15:10). The NT's claim that Jesus fulfilled 'all righteousness' (Matt 3:15) is the fulfillment of David's psalm: where David kept YHWH's ways imperfectly and provisionally, Christ kept them perfectly and permanently — establishing a righteousness that his people receive by faith rather than generate by performance.</p>",
        "23": "<p>'For all his rules were before me, and his statutes I did not put away from me.' The ideal Deuteronomic king who meditates on the Torah day and night (Deut 17:19; Ps 1:2) finds its fulfillment in Christ, who is himself the incarnate Word. John 1:1: 'In the beginning was the Word.' He did not merely observe Torah externally; he is the Torah's living embodiment. Matt 5:17: 'I have not come to abolish the Law or the Prophets but to fulfill them.' Every statute and rule is not only before Christ's eyes but is expressed in his person and life.</p>",
        "24": "<p>'I was blameless before him, and I kept myself from guilt.' <em>Tāmîm</em> (blameless/perfect) is the character standard that only Christ fully meets. Heb 4:15: 'one who in every respect has been tempted as we are, yet without sin.' 1 Pet 1:19: 'a lamb without blemish or spot.' Where David's blamelessness is covenant-faithfulness with ongoing moral failure requiring confession and restoration, Christ's blamelessness is absolute — the spotless sacrifice whose unblemished character makes him the perfect offering for the sins of those who are not blameless.</p>",
        "25": "<p>'Therefore YHWH has recompensed me according to my righteousness.' The covenant principle — faithfulness receives vindication — is exhaustively fulfilled in the resurrection. The resurrection is the Father's public declaration that Christ's righteousness was accepted, his sacrifice was sufficient, his death was expiatory. Acts 17:31: God 'has given assurance to all by raising him from the dead.' The resurrection is the divine recompense for the righteous life and atoning death of the anointed Son — the covenant principle of vv21-25 working at the level of eschatological vindication.</p>",
        "26": "<p>'With the merciful you show yourself merciful; with the blameless man you show yourself blameless.' The divine-mirror principle finds its ultimate expression in Christ's mediation. The mercy Christ shows — 'Father, forgive them, for they know not what they do' (Luke 23:34) — is the mirror of the Father's mercy. Christ mediates the mercy of God to those who are not themselves merciful or blameless, enabling them to receive the mercy they would otherwise be excluded from. He stands in the gap as the blameless one on behalf of those who are not blameless.</p>",
        "27": "<p>'With the pure you show yourself pure, and with the crooked you make yourself seem tortuous.' Christ's purity is the standard against which all human crookedness is revealed. John 3:19-20: 'the light has come into the world, and people loved the darkness rather than the light because their works were evil.' The coming of the Pure One into a crooked world both reveals the crookedness and provides the remedy — the same light that exposes is the light that heals. His purity is not a rebuke to be endured but a grace to be received.</p>",
        "28": "<p>'You save a humble people, but your eyes are on the haughty to bring them down.' Christ is the embodiment of the humble people who are saved — 'I am gentle and lowly in heart' (Matt 11:29); 'he humbled himself by becoming obedient to the point of death' (Phil 2:8). And Christ is the agent of the bringing-down of the haughty: his ministry consistently overturns human hierarchies of honor (Luke 14:11; 18:14). The divine principle of v28 is not an abstract law but a Person — the humble one who was exalted (Phil 2:9) and who saves all who come to him in humility.</p>",
        "29": "<p>'For you are my lamp, O YHWH, and my God lightens my darkness.' Christ is 'the light of the world' (John 8:12; 9:5) — the ultimate fulfillment of the lamp imagery. YHWH who was David's lamp is now incarnate in the one who says 'I am the light of the world; whoever follows me will not walk in darkness, but will have the light of life.' The lamp metaphor for divine guidance (Ps 119:105: 'your word is a lamp to my feet') culminates in the person of Christ, in whom the divine Word and divine Light are identical (John 1:1-9).</p>",
        "30": "<p>'For by you I can run against a troop, and by my God I can leap over a wall.' Christ's authority enables his followers to do what they cannot do by natural capacity — 'I can do all things through him who strengthens me' (Phil 4:13). The divine-empowerment principle (David runs against troops only through YHWH) is fulfilled in the Spirit's empowerment of the church: Acts 1:8, 'you will receive power when the Holy Spirit has come upon you.' The impossible mission — proclaiming the gospel to all nations — is accomplished through the same divine-empowerment principle David sings about here.</p>",
        "31": "<p>'This God — his way is perfect; the word of YHWH proves true; he is a shield for all those who take refuge in him.' Christ is 'the same yesterday and today and forever' (Heb 13:8) — the perfect way (<em>darKô tāmîm</em>) made personal. John 14:6: 'I am the way, and the truth, and the life.' The 'way of YHWH' that is perfect is not merely a path but the Person of the Son. The word that proves true (<em>ṣĕrûpâ</em>, refined/tested) is identified in John 1:1 as the eternal Word who became flesh — the tested-and-proven Word now accessible in human form.</p>",
        "32": "<p>'For who is God, but YHWH? And who is a rock, except our God?' The monotheistic claim of the psalm is fulfilled in the NT's confession of Christ's divine identity. John 10:30: 'I and the Father are one.' The rock — YHWH's exclusive claim in 2 Sam 22 — is applied to Christ in 1 Cor 10:4 ('the Rock was Christ') and 1 Pet 2:6-8 (Christ as the cornerstone). The theological move is stunning: the one who in 2 Sam 22 is called YHWH-the-only-rock is the same one Paul and Peter identify as Christ. The psalm's monotheism is fulfilled in Trinitarian Christology.</p>",
        "33": "<p>'This God is my strong refuge and has made my way blameless.' Christ is the refuge of his people — Heb 6:18: 'we who have fled for refuge might have strong encouragement to hold fast to the hope set before us.' He is also the one who makes his people's way blameless — not by their own achievement but by imputed righteousness: 'you are in Christ Jesus, who became to us wisdom from God, righteousness and sanctification and redemption' (1 Cor 1:30). The blameless way God makes for his people runs through the blameless Person of his Son.</p>",
        "34": "<p>'He made my feet like the feet of a deer and set me secure on the heights.' The sure-footed security on dangerous terrain is the spiritual reality Christ gives his people: 'I give them eternal life, and they will never perish, and no one will snatch them out of my hand' (John 10:28). The security of covenant relationship with the divine shepherd — standing firm on heights that would otherwise be fatal — is the believer's position in Christ. Jude 24: 'to him who is able to keep you from stumbling and to present you blameless before the presence of his glory.'</p>",
        "35": "<p>'He trains my hands for war, so that my arms can bend a bow of bronze.' Christ as the one who equips for spiritual warfare: 'Put on the whole armor of God' (Eph 6:11-17). The armor Paul lists — truth, righteousness, gospel-readiness, faith, salvation, the word of God — is the spiritual equipment corresponding to the physical equipping David describes. The Warrior-King who trained David's hands for physical warfare is the risen Christ who equips his people for the spiritual warfare of the age between his resurrection and return.</p>",
        "36": "<p>'You have given me the shield of your salvation, and your gentleness made me great.' The 'shield of salvation' (Eph 6:16: 'the shield of faith') and the divine gentleness/meekness (<em>ʿanwâ</em>) that makes great are both Christological. Christ is the Gentle One (Matt 11:29: 'I am gentle and lowly in heart') whose gentleness is itself the vehicle of his power. The counter-intuitive claim — that divine meekness makes great — is the theology of the cross: the weakness of God is stronger than human strength (1 Cor 1:25), and the meek inherit the earth (Matt 5:5).</p>",
        "37": "<p>'You gave a wide place for my steps under me, and my feet did not slip.' Christ gives his people secure footing through the Spirit's internal work. Rom 8:38-39: 'neither death nor life, nor angels nor rulers, nor things present nor things to come, nor powers, nor height nor depth, nor anything else in all creation, will be able to separate us from the love of God in Christ Jesus our Lord.' The spacious-place security that David experiences as YHWH's covenant faithfulness to him is, for believers, the unassailable security of being united to the one who died, rose, and intercedes for them.</p>",
        "38": "<p>'I pursued my enemies and destroyed them, and did not turn back until they were consumed.' Christ's pursuit and destruction of his enemies is described in NT eschatological terms: 1 Cor 15:25-26: 'he must reign until he has put all his enemies under his feet. The last enemy to be destroyed is death.' The relentless pursuit that David describes as military victory is the pattern of Christ's cosmic rule — he does not rest until every enemy is subdued. The final enemy (death) is destroyed at the resurrection of the dead, completing the victory that began on Easter morning.</p>",
        "39": "<p>'I consumed them; I thrust them through, so that they did not rise; they fell under my feet.' The enemies-under-feet imagery is the NT's primary lens for understanding Christ's exaltation. Ps 110:1 ('sit at my right hand until I make your enemies your footstool') is the most-cited OT verse in the NT. Eph 1:22: 'he put all things under his feet and gave him as head over all things to the church.' The fallen-enemies-under-feet of David's victory hymn is the pattern of Christ's post-resurrection authority — all things subject to the exalted Son, for the benefit of his body.</p>",
        "40": "<p>'For you equipped me with strength for the battle; you made those who rise against me sink under me.' The Christ who was himself equipped by the Father — 'The Father who sent me has himself given me a commandment — what to say and what to speak' (John 12:49); 'the Father is greater than I' (John 14:28) — is the Son who acts in and through the Father's empowering. The incarnational kenosis (Phil 2:7: he 'emptied himself') means that the Son accomplished his mission in human dependence on the Father's equipping — the same divine-empowerment structure David describes in v40.</p>",
        "41": "<p>'You made my enemies turn their backs to me, those who hated me, and I destroyed them.' The turning of enemies before the anointed king is the pattern fulfilled in Christ's resurrection triumph. Col 2:15: 'he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him.' The cross appeared to be the ultimate defeat — the enemies prevailing — but the resurrection revealed it as the ultimate victory: the powers that thought they had won turned their backs and were publicly exposed as defeated. The great reversal of Easter is the fulfillment of v41.</p>",
        "42": "<p>'They looked, but there was none to save; they cried to YHWH, but he did not answer them.' The unanswered cry of those who are outside covenant relationship points to the seriousness of the final judgment. Matt 7:22-23: 'Many will say to me, Lord, Lord, did we not prophesy in your name … then will I declare to them, I never knew you.' The same God who answers David's cry and Christ's prayer does not answer those who are not in covenant relationship with him — not arbitrary exclusion but the structural consequence of having rejected the covenant. The unanswered cry of v42 is the shadow of the 'outer darkness' in Jesus's parables.</p>",
        "43": "<p>'I beat them fine as the dust of the earth; I crushed them and stamped them down like the mire of the streets.' The complete subjugation of enemies reaches its ultimate form in the final judgment, where all anti-covenant powers are destroyed. Rev 20:14: 'death and Hades were thrown into the lake of fire.' The crushing and stamping that David sings as military victory is the type of Christ's ultimate conquest — not a military campaign but the final dissolution of everything that opposes the reign of God. The dust imagery points to Gen 3:14 (the serpent's head crushed).</p>",
        "44": "<p>'You delivered me from strife with my people; you kept me as the head of the nations; people whom I had not known served me.' Christ is 'the head of all rule and authority' (Col 2:10); 'the ruler of kings on earth' (Rev 1:5). The nations served David; the nations belong to Christ — 'all authority in heaven and on earth has been given to me' (Matt 28:18). The universal lordship that David sings about as a covenant expansion (from one people to all nations) is fulfilled in Christ's cosmic headship: the one who was rejected by his own people (John 1:11) is installed as Lord of all.</p>",
        "45": "<p>'Foreigners came cringing to me; as soon as they heard of me, they obeyed me.' The obedience of the nations to the Davidic king at the report of his deeds is the missional template: 'the obedience of faith among all the nations' (Rom 1:5) that Paul describes as his apostolic commission. The Gentile mission is the fulfillment of v45 — foreigners who hear of Christ's deeds (his death and resurrection) come in faith-submission. The cringing before David becomes the bowing of every knee (Phil 2:10) before the name of Jesus, the Davidic Messiah.</p>",
        "46": "<p>'Foreigners lost heart and came trembling out of their fortresses.' The nations' submission to the Davidic king reaches its eschatological form in Rev 21:24-26: 'the nations will walk by its light, and the kings of the earth will bring their glory into it.' The nations who brought tribute to David — sometimes by compulsion — will bring their glory to the New Jerusalem voluntarily. The trembling-submission of v46 is transformed: not conquest-surrender but the voluntary honoring of the Lamb by the redeemed from every tribe and tongue and people and nation (Rev 5:9).</p>",
        "47": "<p>'YHWH lives!' — the affirmation of the living God is fulfilled in the resurrection confession. Rom 14:9: 'Christ died and lived again, that he might be Lord both of the dead and of the living.' The cry <em>ḥay YHWH</em> is the OT's equivalent of the NT's resurrection confession. The God who answered David's cry by demonstrating that he is living — not the silent dead idols of the nations — demonstrates his living nature supremely in raising Jesus from the dead. 'He is not the God of the dead, but of the living' (Matt 22:32) applies to the resurrection of Christ what 2 Sam 22:47 affirms about YHWH.</p>",
        "48": "<p>'The God who gave me vengeance and brought down peoples under me.' The vengeance-and-vindication theme finds its ultimate expression in Christ's resurrection and final judgment. Rom 12:19 (Deut 32:35): 'vengeance is mine, I will repay, says the Lord.' Christ does not take personal revenge; he entrusts judgment to the Father. But the Father's vindication of the crucified Son is itself the ultimate act of covenant justice: the one who was unjustly condemned is declared righteous by the resurrection (1 Tim 3:16: 'vindicated by the Spirit').</p>",
        "49": "<p>'Who rescued me from my enemies; yes, you exalted me above those who rose against me; you delivered me from the man of violence.' The triple rescue statement — from enemies, from those who rise against, from the violent — covers the full spectrum of Christ's opponents: the religious establishment, the Roman imperial power, and the devil (the ultimate 'man of violence'). All three conspired at the cross; all three were overcome by the resurrection. 1 John 3:8: 'the reason the Son of God appeared was to destroy the works of the devil.' The rescue of v49 is the destruction of all Christ's enemies, which is simultaneously the rescue of his people.</p>",
        "50": "<p>'For this I will praise you, YHWH, among the nations, and sing to your name.' Paul quotes this verse directly in Romans 15:9 as one of four OT texts proving that the Gentile mission was always YHWH's plan. The full chain: the Davidic king sings praise among the nations (2 Sam 22:50); the Gentiles rejoice with God's people (Deut 32:43); all peoples praise YHWH (Ps 117:1); the root of Jesse arises to rule the nations (Isa 11:10). Christ is the Davidic king of v50 who leads the praise of the nations — Heb 2:12: 'I will tell of your name to my brothers; in the midst of the congregation I will sing your praise.'</p>",
        "51": "<p>'Great salvation he brings to his king, and shows steadfast love to his anointed, to David and his offspring forever.' The closing verse is the theological summit of 2 Samuel 22 and the entire David narrative. <em>Māšîaḥô</em> — his anointed one, his Messiah. The <em>ḥesed</em> to the Davidic offspring <em>ʿad-ʿôlām</em> (forever) is the Davidic covenant in its most concentrated form. Gal 3:16 applies the same seed-logic that 2 Sam 7 establishes: 'to your offspring,' which is Christ. The eternal covenant-loyalty YHWH pledges to David's seed is fulfilled in the resurrection-life of the one seed who is both David's son and David's Lord (Mark 12:35-37). The last word of the David narrative is the first word of Christology.</p>"
    },
    "23": {
        "1": "<p>'The oracle of David, the son of Jesse, the oracle of the man who was raised on high, the anointed of the God of Jacob, the sweet psalmist of Israel.' The four titles — son of Jesse, man raised on high, anointed of God, sweet psalmist — are all fulfilled christologically in Jesus. He is the son of Jesse by Davidic genealogy (Matt 1:5-6; Luke 3:32); he is the man raised on high by resurrection and ascension (Acts 2:33; Eph 1:20); he is the Anointed One (<em>māšîaḥ/christos</em>) par excellence; he is the voice through whom the Spirit speaks the psalms (Heb 2:12: 'I will sing your praise'). David's four titles are the titles of his greater Son.</p>",
        "2": "<p>'The Spirit of YHWH speaks by me; his word is on my tongue.' Christ is the Spirit-inspired speaker par excellence — and more: he is the Word itself (John 1:1). 'He whom God has sent utters the words of God, for he gives the Spirit without measure' (John 3:34). The Spirit who inspired David's words is the Spirit who rests without measure on Christ. 1 Pet 1:11 identifies the Spirit of Christ as the inspiration of all the OT prophets — the prophetic Spirit who spoke through David is identified as Christ's own Spirit, reaching back through history to prepare for his coming.</p>",
        "3": "<p>'The God of Israel has spoken; the Rock of Israel has said to me: When one rules justly over men, ruling in the fear of God.' The ideal king of David's last words — just rule + fear of God — is the Isaianic Messiah: 'the Spirit of the LORD shall rest upon him … he shall judge with righteousness … with faithfulness he shall gird his loins' (Isa 11:1-5). Jesus is the fulfillment of this ideal: he judges with perfect justice (John 5:22: 'the Father judges no one, but has given all judgment to the Son'); he lives in perfect fear of God (Heb 5:7: 'he was heard because of his reverence').</p>",
        "4": "<p>'He dawns on them like the morning light, like the sun shining forth on a cloudless morning, like rain that makes grass sprout from the earth.' Three messianic images fulfilled in Christ: morning light — Luke 1:78-79: 'the sunrise shall visit us from on high to give light to those who sit in darkness'; sun on a cloudless morning — Mal 4:2: 'the sun of righteousness shall rise with healing in its wings'; rain making grass sprout — Isa 55:10-11: 'as the rain and snow come down from heaven … so shall my word be.' Christ is simultaneously the light of the world, the sun of righteousness, and the life-giving rain of the new creation.</p>",
        "5": "<p>'For does not my house stand so with God? For he has made with me an everlasting covenant, ordered in all things and secure.' The <em>bĕrîṯ ʿôlām</em> (everlasting covenant) grounding David's confidence is mediated through Christ and fulfilled in his blood. Heb 13:20: 'the God of peace who brought again from the dead our Lord Jesus, the great shepherd of the sheep, by the blood of the eternal covenant.' The blood of the eternal covenant is Christ's blood — the new covenant ratified by the sacrifice that fulfills all that the Davidic covenant pointed toward. Every 'all things and secure' that David rests in is made certain by the resurrection of the covenant mediator.</p>",
        "6": "<p>'But worthless men are all like thorns that are thrust away, for they cannot be taken with the hand.' The <em>bĕliyyaʿal</em> (worthless/lawless ones) who are like thorns irresistibly points toward the crown of thorns placed on Christ at his trial (Matt 27:29; Mark 15:17; John 19:2). Christ wore the symbol of the worthless, the <em>bĕliyyaʿal</em> that must be thrust away — he bore the thorn-curse (Gen 3:18: 'thorns and thistles it shall bring forth') in his own flesh. The thorns that represent anti-covenant disorder and deserve to be burned are gathered and placed on the head of the just king — the one who should wear a golden crown bears instead the curse-crown of the worthless.</p>",
        "7": "<p>'They are not taken with the hand; the man who touches them arms himself with iron and the handle of a spear, and they are utterly consumed with fire in their place.' The iron-and-spear motif of handling thorns finds a specific echo in John 19:34: the soldier pierces Jesus's side with a spear after the crucifixion. Christ, who bore the thorn-crown (v6) and was pierced by the spear (v7 echo), is the just king who touches the thorns that no one can safely hold — he absorbs the thorn-curse so that those who are in him might escape the consuming fire. The same fire that destroys the <em>bĕliyyaʿal</em> was endured by Christ on behalf of his people.</p>",
        "8": "<p>The gibbôrîm (mighty men) of David — the warrior-band that gathered to him in the Adullam cave — is a type of the community of those who follow Christ. They gathered to him when he was an outlaw, a rejected fugitive, before he was king. The church is similarly gathered to Christ in the period before his kingdom is fully visible — joining the one who was 'despised and rejected by men' (Isa 53:3) before the kingdom comes in its fullness. The gibbôrîm's loyalty to David as fugitive-king before his enthronement is the pattern of discipleship: following the Lord not only in his glory but in his humiliation.</p>",
        "9": "<p>Eleazar son of Dodo — standing alone when the Israelites retreated. The one who stands firm when others flee embodies the calling of every disciple: 'Be watchful, stand firm in the faith, act like men, be strong' (1 Cor 16:13). The gibbôrîm's individual acts of valor against overwhelming odds are the pattern of the community of Christ — those who hold the line when the battle seems lost. Paul's armor-of-God passage (Eph 6:13: 'that you may be able to withstand in the evil day, and having done all, to stand firm') draws on exactly this warrior-standing-alone imagery.</p>",
        "10": "<p>'He stood his ground and struck down the Philistines until his hand was weary and his hand clung to the sword. And YHWH brought about a great victory that day.' The hand-clinging-to-the-sword image is exhaustion-without-abandonment — continued faithfulness past the point of natural endurance. This is the call to perseverance in the NT: 'let us not grow weary of doing good, for in due season we will reap, if we do not give up' (Gal 6:9); 'run with endurance the race that is set before us' (Heb 12:1). YHWH bringing the great victory is the theological reminder that endurance in ministry is empowered by divine faithfulness, not human stamina.</p>",
        "11": "<p>Shammah son of Agee — defending a lentil field while others fled. The ordinary location of extraordinary faithfulness — a lentil field, not a famous battlefield — is characteristic of the kingdom: 'whoever is faithful in a very little is also faithful in much' (Luke 16:10). Christ commends the widow's two mites (Mark 12:41-44), the washing of feet (John 13:14-15), and the cup of cold water given in his name (Matt 10:42). The gibbôrîm's valor in small places is the pattern of the kingdom of God, where significance is measured not by the importance of the location but by faithfulness to the task.</p>",
        "12": "<p>'But he took his stand in the midst of the plot and defended it and struck down the Philistines, and YHWH worked a great victory.' The divine-victory refrain after human faithfulness is the NT theology of synergism: 'I worked harder than any of them, though it was not I, but the grace of God that is with me' (1 Cor 15:10). Paul's productivity is both genuinely his and entirely God's grace — the same integration 2 Sam 23:12 shows: Shammah's stand was real and valiant; YHWH's victory was decisive and divine. The two are not in competition.</p>",
        "13": "<p>'And three of the thirty chief men went down … to David at the cave of Adullam.' The cave of Adullam is the gathering place of the rejected and the desperate (1 Sam 22:2: 'everyone who was in distress, and everyone who was in debt, and everyone who was bitter in soul gathered to him'). It is an image of the church: those who gather to Christ are not the strong and sufficient but the weary and burdened — 'Come to me, all who labor and are heavy laden, and I will give you rest' (Matt 11:28). Christ gathers his people not in the palace but in the cave.</p>",
        "14": "<p>'David was then in the stronghold, and the garrison of the Philistines was then at Bethlehem.' Christ's first advent: born in Bethlehem, his hometown occupied by foreign power. Luke 2:1-7 sets the birth of Christ in the context of Roman imperial power — a census ordered by Caesar, Bethlehem occupied, the child born in the animals' feeding-place because there was no room. The son of David born in David's town under foreign occupation is the fulfillment of the Bethlehem-in-enemy-hands pattern — the rightful king present in his own territory as a refugee.</p>",
        "15": "<p>'And David said longingly, Oh, that someone would give me water to drink from the well of Bethlehem that is by the gate!' The king's longing for the water of his hometown — when Bethlehem is occupied and inaccessible — is the longing of the one who was thirsty. John 19:28: 'Jesus, knowing that all was now finished, said (to fulfill the Scripture), I thirst.' Christ's thirst on the cross is the fulfillment of the suffering righteous king's longing — the Davidic king deprived of water, thirsty in extremity. And Christ is also the one who gives the water of life: John 4:14 — 'whoever drinks of the water that I will give him will never be thirsty again.'</p>",
        "16": "<p>'Then the three mighty men broke through the camp of the Philistines and drew water out of the well of Bethlehem … and carried and brought it to David.' The loyal service of the three warriors — risking their lives for a gesture of devotion to their king — is the pattern of sacrificial ministry. Phil 2:30: Epaphroditus 'nearly died for the work of Christ, risking his life to complete what was lacking in your service to me.' The gibbôrîm's blood-risking service for their king becomes the model for apostolic co-workers who risk their lives in the service of the Servant-King. Their devotion to David's expressed longing is the pattern of Spirit-led service to Christ's mission.</p>",
        "17": "<p>'He would not drink it. He poured it out to YHWH and said, Far be it from me, YHWH, that I should do this. Shall I drink the blood of the men who went at the risk of their lives?' David's refusal to consume blood-cost water and his pouring it as a libation to YHWH is a direct type of Christ's self-giving. Phil 2:17: 'even if I am being poured out as a drink offering over the sacrifice and service of your faith.' The king who pours out costly-blood water to God rather than consuming it for himself is the type of the king who poured out his own life — 'he poured out his soul to death' (Isa 53:12) — as the ultimate libation, the drink offering of the new covenant.</p>",
        "18": "<p>Abishai the brother of Joab — the most loyal of the Zeruiah brothers, who repeatedly offered himself in protection of the king. His loyalty to David through every crisis (civil war, Absalom's rebellion, the giant's attack) is the pattern of covenant faithfulness to the Davidic king. The community of Christ is called to similar unflinching loyalty — 'if we endure, we will also reign with him; if we deny him, he will also deny us' (2 Tim 2:12). The great test of the gibbôrîm's loyalty was whether they stood with David in his humiliation and danger — the same test the disciples faced and largely failed (Mark 14:50), and which the Spirit enables them to pass after Pentecost.</p>",
        "19": "<p>'He was the most renowned of the thirty and became their commander, but he did not attain to the three.' The ranking within the gibbôrîm — distinctions of honor based on specific acts of valor — anticipates Christ's teaching on kingdom honors: 'many who are first will be last, and the last first' (Matt 19:30); 'whoever would be great among you must be your servant' (Matt 20:26). The kingdom has real distinctions of honor (Matt 5:19: 'whoever does them and teaches them will be called great in the kingdom of heaven') but those honors are assigned by a different logic than human rank-by-birth or rank-by-power. The gibbôrîm's earned distinctions model this: honor through specific acts of faithful service.</p>",
        "20": "<p>Benaiah son of Jehoiada — killing a lion in a pit on a snowy day; killing an Egyptian with his own spear. The specific, improbable exploits of Benaiah model the call to bold, creative faithfulness in adverse conditions: cold weather, confined space, armed opponent. Christ's call to his disciples consistently involves adverse conditions: 'I am sending you out as sheep in the midst of wolves' (Matt 10:16); 'in the world you will have tribulation' (John 16:33). The gibbôrîm are not called to comfortable service but to dangerous faithfulness — and the record of their specific acts is preserved eternally.</p>",
        "21": "<p>'He also went down and struck down a lion in a pit on a snowy day. He struck down an Egyptian, a handsome man. The Egyptian had a spear in his hand, but Benaiah went down to him with a staff and snatched the spear out of the Egyptian's hand and killed him with his own spear.' Christ used the weapons of the enemy against him: the cross was meant to be the ultimate shaming of the rebel — execution as a criminal. But Christ transformed the cross into the instrument of the enemy's defeat (Col 2:15: 'triumphing over them in it'). Benaiah taking the enemy's weapon and killing him with it is a type of Christ taking the curse of the law (Gal 3:13) — the enemy's weapon — and through it defeating the one who wielded it.</p>",
        "22": "<p>'These things Benaiah son of Jehoiada did, and won a name beside the three mighty men.' Winning a name through specific acts of valor is the pattern of kingdom honor. Phil 2:9: Christ 'was given the name that is above every name' — through the specific act of his obedient death and resurrection. The gibbôrîm win names through specific acts of courage; Christ wins the Name through the specific act of the cross and resurrection. And his followers share in his honor: Rev 2:17: 'to the one who conquers I will give … a white stone, with a new name written on the stone that no one knows except the one who receives it.'</p>",
        "23": "<p>'He was renowned among the thirty, but he did not attain to the three. And David set him over his bodyguard.' The king placing his most valiant servant over his bodyguard is the pattern of kingdom appointments: 'you have been faithful over a little; I will set you over much' (Matt 25:21, 23). Benaiah's posting reflects Christ's method of kingdom governance — those who demonstrate faithfulness and valor in the present order receive authority in the coming one. The parable of the talents and pounds (Luke 19:11-27) promises governmental authority in the kingdom to those who are faithful with what they have been entrusted now.</p>",
        "24": "<p>Asahel brother of Joab — fleet-footed warrior killed in the early civil war (2 Sam 2:18-23). His inclusion at the head of the Thirty despite his early death signals that the gibbôrîm list preserves a permanent honor-record: death does not erase the name from the roll of the faithful. This is the covenant theology of the resurrection: 'He is not the God of the dead, but of the living' (Matt 22:32). Those who die in the service of the Davidic king are not forgotten — their names are kept in the book. Rev 20:12: 'the dead were judged by what was written in the books.'</p>",
        "25": "<p>The geographic range of the Thirty reflects the pan-Israelite character of the gibbôrîm — warriors from multiple tribes bound to the Davidic throne by personal loyalty rather than tribal affiliation. This is the NT pattern of the church: 'there is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus' (Gal 3:28). The unifying loyalty is to the person of the king, not to tribal or ethnic identity. The diverse origins of the Thirty prefigure the diverse origins of the church gathered to the greater Davidic king.</p>",
        "26": "<p>The Benjaminite presence in the Thirty — warriors from Saul's own tribe giving their personal loyalty to David — is a picture of reconciliation across the tribal divide that the civil war had created. In Christ, the ultimate reconciliation: those who were enemies are made 'fellow citizens with the saints and members of the household of God' (Eph 2:19). The Benjaminite warriors who chose David over their own tribal loyalty are types of those who leave behind former allegiances to follow Christ — the one whose kingdom crosses every ethnic, social, and familial boundary.</p>",
        "27": "<p>Abiezer the Anathothite — from the village that will produce Jeremiah, the prophet of the new covenant (Jer 31:31-34). The geographical connection is providential: the village that supplies warriors to the Davidic throne is the village from which comes the prophet who articulates the deepest covenant promises of the OT. The community that serves the earthly Davidic king generates the prophet who announces the coming of the heavenly Davidic king. Geography and history are woven together in the covenant purposes of God.</p>",
        "28": "<p>The individual names of the Thirty are preserved because each represents a specific person in covenant relationship with the Davidic king. This is the theology of individual knowledge within corporate belonging: 'I am the good shepherd. I know my own and my own know me' (John 10:14). Christ knows each of his people by name — 'he calls his own sheep by name' (John 10:3). The roll of the Thirty is the prototype of the Lamb's Book of Life (Rev 21:27): specific names, specifically known by the king they served.</p>",
        "29": "<p>The gibbôrîm from the Carmel region — the territory connected to Nabal, Abigail, and David's early Judean loyalists — represent the conversion of former relationships into permanent commitment. David's early wilderness coalition, formed out of necessity and mutual protection, matured into the Thirty's institutional loyalty. The disciples' movement from emergency-followers (called in crisis) to the community of the apostles (established in mission) follows the same pattern: early loose association crystallized into permanent, named, institutional commitment to the Risen Lord.</p>",
        "30": "<p>Hiddai of the brooks of Gaash — from the Ephraim hill country, near Joshua's tomb. The location connects the gibbôrîm to the entire sweep of the conquest narrative: the land Joshua led Israel into now produces warriors for the Davidic king. The Davidic covenant's expansion beyond Judah into the northern tribal territories is the social reality behind the list. Christ's kingdom expansion follows the same geography — 'Jerusalem and in all Judea and Samaria and to the end of the earth' (Acts 1:8) — beginning at the center and expanding outward to gather the scattered.</p>",
        "31": "<p>The warriors from the far north — Shaalbonites, associated with Dan and Naphtali — represent the full geographic scope of the Israelite covenant community gathered around the Davidic throne. The eschatological vision of Isaiah — 'nations shall come to your light, and kings to the brightness of your rising' (Isa 60:3) — is grounded in this already-visible reality: from every part of the land, individuals are gathering personally to the Davidic king. The Thirty from north to south are the first-fruits of the eschatological gathering.</p>",
        "32": "<p>Jonathan son of Shammah the Hararite — the son following his father into service to the Davidic king. Multi-generational covenant faithfulness to the Davidic throne is the pattern Christ's community is called to: 'teaching them to observe all that I have commanded you … to the end of the age' (Matt 28:20). The faith that Paul describes as dwelling 'first in your grandmother Lois and your mother Eunice and now, I am sure, in you as well' (2 Tim 1:5) is the gibbôrîm-pattern of covenant loyalty passing from generation to generation in the service of the Davidic king.</p>",
        "33": "<p>The repeated clan identifiers (Hararite appears three times) reflect the community character of covenant service: individual valor exists within family and clan networks of mutual loyalty. The church as body (1 Cor 12) and as household (Eph 2:19) reflects the same truth: individual gifts and acts of faithfulness operate within a communal structure of belonging. No gibbôr stands alone — he stands within his clan, within the Thirty, within the covenant community around the Davidic king. The lone-hero mythology is corrected by the list's communal structure.</p>",
        "34": "<p>Eliphelet son of Ahasbai of Maacah — from an Aramean kingdom. The international diversity of the Thirty, which includes Aramean-affiliated warriors alongside Israelites, anticipates the church's international composition. The missionary commission ('all nations,' Matt 28:19) is grounded in the already-existing reality that the Davidic king's community was never purely ethnically Israelite. Uriah, Eliphelet, Zelek the Ammonite — the Thirty are a multi-ethnic covenant community, the prototype of what the Spirit-filled church becomes at Pentecost when 'every nation under heaven' (Acts 2:5) hears the apostolic message.</p>",
        "35": "<p>Eliam son of Ahithophel the Gilonite — whose family connection to Bathsheba makes Ahithophel's betrayal a deeply personal wound, and whose own name is preserved in the roll of the faithful even as his father's name is synonymous with betrayal. The juxtaposition of Eliam (loyal son) and Ahithophel (betraying father) within the same family is the reminder that covenant faithfulness is not hereditary — it is chosen. Christ's community includes those whose families were faithless (Rahab, Ruth, Eliam) as well as those whose families were faithful. Personal covenant commitment, not family status, is the ground of belonging.</p>",
        "36": "<p>The individual names of the Thirty — each one a specific human being whose specific acts of loyal service are preserved — is the OT's statement about the value of the particular person. The God who knows each star by name (Ps 147:4; Isa 40:26) knows each of his people by name. Christ's parable of the lost sheep (Luke 15:4-7) — leaving ninety-nine to find one — applies the same specificity to the kingdom: each individual is specifically sought, specifically known, specifically named in the register of the faithful.</p>",
        "37": "<p>Igal son of Nathan from Zobah — a warrior from conquered Aram in the service of the Davidic king. The conquered-becoming-covenant-servants is the pattern of the gospel's expansion: those who were formerly enemies become participants in the Davidic community. Eph 2:12-13: 'remember that you were at that time separated from Christ, alienated from the commonwealth of Israel … but now in Christ Jesus you who once were far off have been brought near.' The Aramean warrior brought near to the Davidic throne is the type of every Gentile believer brought near to the greater Davidic king.</p>",
        "38": "<p>Zelek the Ammonite — from the nation against whom David was simultaneously at war, now serving in his elite corps. The radical reversal: personal enmity between nations does not preclude individual incorporation into the covenant community. This is the logic Paul explicates in Romans 11 (the olive tree: wild branches grafted in) and Eph 2:14-16 (Christ breaking down the dividing wall of hostility). The Ammonite warrior in the Davidic Thirty is the lived-out prototype of what the gospel accomplishes: creating one new humanity from those who were formerly enemies.</p>",
        "39": "<p>'Uriah the Hittite — thirty-seven in all.' The list ends with Uriah — the Hittite warrior whose murder David engineered, whose name David could have omitted, whose inclusion here is an act of canonical preservation of the innocent. His name at the end of the list ensures that his memory is honored precisely in the place where honor is most permanently recorded. Christ is the one who ultimately vindicates the innocent whose blood was shed by the powerful — 'shall not God give justice to his elect, who cry to him day and night?' (Luke 18:7). Uriah's name preserved in the roll of the faithful is a type of the resurrection's vindication of all who died unjustly in the service of a king who failed them — but who are remembered by the king who does not fail.</p>"
    }
}


def main():
    existing = load_comm('mkt-christ', '2samuel')
    merge_comm(existing, SAMUEL2_CHRIST_CH22_23)
    save_comm('mkt-christ', '2samuel', existing)

    ch22 = existing.get('22', {})
    ch23 = existing.get('23', {})
    print(f'ch 22: {len(ch22)} verse entries')
    print(f'ch 23: {len(ch23)} verse entries')

    # completeness check
    interlinear_path = ROOT / 'data' / 'interlinear' / '2samuel.json'
    if interlinear_path.exists():
        il = json.loads(interlinear_path.read_text())
        for ch_num in ['22', '23']:
            il_verses = set(il.get(ch_num, {}).keys())
            comm_verses = set(existing.get(ch_num, {}).keys())
            missing = il_verses - comm_verses
            if missing:
                print(f'  ch {ch_num} missing: {sorted(missing, key=int)}')
            else:
                print(f'  ch {ch_num}: complete ({len(comm_verses)}/{len(il_verses)} verses)')


if __name__ == '__main__':
    main()
